param($MaxIterations=3); . "$PSScriptRoot\Config\DualLoop.Config.ps1"; $agents = "$Root\Agents"; if (!(Test-Path $agents)) { throw "Agents missing" }; for ($i=1; $i -le $MaxIterations; $i++) { if (Test-Path $KillFile) { break }; if (!(Test-Path $StateFile)) { @{iteration=0; last_file=$SeedFile; created=(Get-Date).ToString("o")} | ConvertTo-Json | Set-Content $StateFile -Encoding UTF8 }; $state = Get-Content $StateFile -Raw | ConvertFrom-Json; $iter = [int]$state.iteration+1; $dir = "$Root\Iterations\iteration_{0:D4}" -f $iter; New-Item -ItemType Directory -Force -Path $dir | Out-Null; $src = $state.last_file; if (!(Test-Path $src)) { $src = $SeedFile }; $a1 = "$dir\Agent1_Expanded.txt"; $a2 = "$dir\Agent2_Pruned.txt"; $a3 = "$dir\Agent3_Final.txt"; & "$agents\Agent1_Expand.ps1" -InputFile $src -OutputFile $a1; & "$agents\Agent2_Pruner.ps1" -InputFile $a1 -OutputFile $a2; & "$agents\Agent3_Synth.ps1" -InputFile $a2 -OutputFile $a3; $state.iteration=$iter; $state.last_file=$a3; $state.last_updated=(Get-Date).ToString("o"); $state | ConvertTo-Json | Set-Content $StateFile -Encoding UTF8; Write-Host "Iteration $iter done: $a3" } 
